export function autoTranslateDesc(text: string, lang: Lang): string {
  if (!text || lang !== 'en') return text;

  // Exact match, then normalized fuzzy match
  const trimmed = text.trim()
  const result = FULL[trimmed] ?? getNormalizedFULL().get(normalize(trimmed))
  if (result) return result

  // Try substring replacements for partial matches — longest first
  let t = text;
  Object.entries(FULL).sort((a,b) => b[0].length - a[0].length).forEach(([es, en]) => {
    if (t.includes(es)) t = t.replace(es, en);
  });

  // ── REMAINING WORD / ARTICLE CLEANUP with word boundaries ──
  const wordMap = [
    // Spanish articles and prepositions that still slip through
    [/\bla\b/g, 'the'], [/\bel\b/g, 'the'], [/\blos\b/g, 'the'], [/\blas\b/g, 'the'],
    [/\bdel\b/g, 'of the'], [/\bde la\b/g, 'of the'], [/\bde los\b/g, 'of the'],
    [/\ben el\b/g, 'in the'], [/\ben la\b/g, 'in the'], [/\ben los\b/g, 'in the'],
    [/\bal\b/g, 'to the'], [/\bcon\b/g, 'with'], [/\bpor\b/g, 'by'],
    [/\bpara\b/g, 'for'], [/\bsobre\b/g, 'on'], [/\bante\b/g, 'before'],
    [/\buna\b/g, 'a'], [/\bun\b/g, 'a'], [/\bsus\b/g, 'its'],
    [/\bsu\b/g, 'its'], [/\bque\b/g, 'that'], [/\bsolo\b/g, 'only'],
    [/\bhasta\b/g, 'until'], [/\bdurante\b/g, 'during'],
    // Military terms
    [/\bbatalla\b/gi, 'battle'], [/\bguerra\b/gi, 'war'], [/\bejército\b/gi, 'army'],
    [/\bejércitos\b/gi, 'armies'], [/\bflota\b/gi, 'fleet'], [/\basedio\b/gi, 'siege'],
    [/\bvictoria\b/gi, 'victory'], [/\bderrota\b/gi, 'defeat'],
    [/\bconquista\b/gi, 'conquest'], [/\binvasión\b/gi, 'invasion'],
    [/\bindependencia\b/gi, 'independence'], [/\brendición\b/gi, 'surrender'],
    [/\bmuertos\b/gi, 'killed'], [/\bbajas\b/gi, 'casualties'],
    [/\bprisioneros\b/gi, 'prisoners'], [/\bparacaidistas\b/gi, 'paratroopers'],
    [/\bsoldados\b/gi, 'soldiers'], [/\bgriegos\b/gi, 'Greeks'],
    [/\bromanos\b/gi, 'Romans'], [/\bpersas\b/gi, 'Persians'],
    [/\begipcios\b/gi, 'Egyptians'], [/\bcartagineses\b/gi, 'Carthaginians'],
    [/\bmongoles\b/gi, 'Mongols'], [/\bvikingos\b/gi, 'Vikings'],
    [/\botomanos\b/gi, 'Ottomans'], [/\bfrancos\b/gi, 'Franks'],
    [/\bsajones\b/gi, 'Saxons'], [/\bcruzados\b/gi, 'Crusaders'],
    [/\bsiglo\b/gi, 'century'], [/\bImperio\b/g, 'Empire'], [/\bimperio\b/g, 'empire'],
    [/\bRepública\b/g, 'Republic'], [/\bRey\b/g, 'King'], [/\brey\b/g, 'king'],
  ];
  wordMap.forEach(([pattern, en]) => { t = t.replace(pattern, en); });

  return t;
}
